    // Split the phrases and create sets for each
    let words1 = new Set(phrase1.split(" "));
    let words2 = new Set(phrase2.split(" "));

    // Calculate the number of unique words in each phrase
    let record1 = words1.size;
    let record2 = words2.size;

    // Calculate the overlapping words and distinct words
    let overlapping = new Set([...words1].filter(x => words2.has(x)));
