<code>
content = """
def sieve_of_eratosthenes(limit):
    limitn = limit + 1
    primes = dict()
    for i in range(2, limitn): 
        primes[i] = True

    for i in list(primes.keys()):
        if primes[i]:
            factors = range(i * 2, limitn, i)
            for f in factors:
                primes[f] = False
    return [i for i in primes if primes[i]]

def first_n_primes(n):
    primes = []
    i = 2
    while len(primes) < n:
        primes_list = sieve_of_eratosthenes(i + 1)
        for prime in primes_list:
            if prime not in primes:
                primes.append(prime)
        i += 1
    return primes[:n]

print(first_n_primes(7))
"""
