import math

def is_prime(n):
    if n < 2:
        return False
    for i in range(2, int(math.sqrt(n)) + 1):
        if n % i == 0:
            return False
    return True

def generate_array(x, y, z):
    # Random number generation
    array = [[[random.randint(-50, 50) for _ in range(z)] for _ in range(y)] for _ in range(x)]
    # Replace prime numbers with their negative values
    for i in range(x):
        for j in range(y):
            for k in range(z):
                if is_prime(array[i][j][k]) and array[i][j][k] > 0:
                    array[i][j][k] *= -1
    return array

def calculate_depth_avg(array, z):
    if z == 0:
        return []
    depth_avgs = []
    for k in range(z):
        total_sum = 0
        count = 0
        for i in range(len(array)):
            for j in range(len(array[i])):
                total_sum += array[i][j][k]
                count += 1
        depth_avgs.append(total_sum / count if count > 0 else 0)
    return depth_avgs

if __name__ == '__main__':
    # scenario 1
    print('Scenario 1: 3x3x3')
    dims1 = (3, 3, 3)
    arr1 = generate_array(*dims1)
