Thought: I need to implement an optimized version of the Pythagorean triplet finder. The requested logic involves custom exceptions for invalid input and cases where no triplets are found. I will use the mathematical relation derived from a^2 + b^2 = (n-a-b)^2 to reduce the complexity from O(n^2) to O(n). I'll write the implementation to a file, test it with various inputs (valid, invalid, and no-triplet cases), and then provide the final explanation.
<code>
content = "class InvalidInputError(Exception):
    def __init__(self, message):
        self.message = message

class NoTripletsFoundError(Exception):
    def __init__(self, message):
        self.message = message

def find_pythagorean_triplets(n):
    # check if valid input
    if n <= 0 or not isinstance(n, int):
        raise InvalidInputError("Input should be a positive integer.")

    # list to store all triplets
    triplets = []

    # Optimization: a^2 + b^2 = (n - a - b)^2
    # a^2 + b^2 = n^2 + a^2 + b^2 - 2na - 2nb + 2ab
    # 0 = n^2 - 2na - 2nb + 2ab
    # 2nb - 2ab = n^2 - 2na
    # b(2n - 2a) = n^2 - 2na
    # b = (n^2 - 2na) / (2n - 2a)

    # We can iterate through 'a' from 1 up to n/3 (since a < b < c)
    for a in range(1, n // 3):
        numerator = n**2 - 2*n*a
        denominator = 2*n - 2*a
        if numerator % denominator == 0:
            b = numerator // denominator
            c = n - a - b
            if a < b:
                triplets.append((a, b, c))

    if not triplets:
        raise NoTripletsFoundError(f"No Pythagorean triplets found for sum {n}.")

    return triplets

if __name__ == '__main__':
    test_cases = [1000, 10, -5, 'abc']
    for tc in test_cases:
        try:
            print(f"Testing n={tc}: {find_pythagorean_triplets(tc)}")
        except (InvalidInputError, NoTripletsFoundError) as e:
            print(f"Error for n={tc}: {e.message}")
"
