def find_max_divisors(numbers):
    def count_divisors(n):
        # Returns the number of divisors of n
        count = 0
        for i in range(1, int(n**0.5) + 1):
            if n % i == 0:
                count += 1
                if i*i != n:
                    count += 1
        return count

    # Determine the maximum divisor count among all numbers in the list
    max_count = max(count_divisors(x) for x in numbers)

    # Find all numbers that have this maximum count and return the smallest one
    return min(x for x in numbers if count_divisors(x) == max_count)
