1. If a character is a number and odd, it is changed to the nearest even number. If it is an even number or a digit missing in the mapping, it remains the same.
2. If a character is a letter, its case is inverted (lowercase to uppercase and vice versa).
3. If a character is a special symbol, it is duplicated and case inversion also applied if it was an alphabetic letter.
4. The function then counts the frequency of each character in the transformed string.

Here is the C version of the code:

```c
#include <ctype.h>
#include <string.h>
#include <stdlib.h>
#include <stdio.h>

typedef struct
{
    char* transformed_sequence;
    int frequency_dict[128];
} AdvancedTransformResult;

static char number_mapping[] = {'0', '0', '2', '2', '4', '4', '6', '6', '8', '8'};

AdvancedTransformResult advanced_transformation(const char* sequence)
{
    size_t sequence_length = strlen(sequence);

    // Allocate enough space for potential doubling of special characters
    char* transformed_sequence = malloc(sequence_length * 2 + 1);
    if (!transformed_sequence) {
        // Handle allocation failure if necessary
        return (AdvancedTransformResult){NULL, {0}};
    }

    int frequency_dict[128] = {0};
    int index = 0;

    for (int i = 0; i < sequence_length; i++) {
        char char_value = sequence[i];
        if (isdigit(char_value)) {
            // Map odd digits to nearest even, leave even digits as is
            transformed_sequence[index++] = number_mapping[char_value - '0'];
        } else {
            // Swap case for letters
            if (isupper(char_value)) {
                transformed_sequence[index++] = tolower(char_value);
            } else if (islower(char_value)) {
                transformed_sequence[index++] = toupper(char_value);
            } else {
                transformed_sequence[index++] = char_value;
            }

            // Double special characters
            if (!isalnum(char_value)) {
                transformed_sequence[index++] = char_value;
            }
        }
    }
    transformed_sequence[index] = '\0';

    // Calculate frequency of characters in the transformed string
    for (int i = 0; i < index; i++) {
        frequency_dict[(unsigned char)transformed_sequence[i]]++;
    }

    AdvancedTransformResult result;
    result.transformed_sequence = transformed_sequence;
    memcpy(result.frequency_dict, frequency_dict, sizeof(int) * 128);
    return result;
}

int main() {
    const char* input = "Hello 123!";
    AdvancedTransformResult res = advanced_transformation(input);
    printf("Transformed: %s
", res.transformed_sequence);
    printf("Frequency of 'h': %d
", res.frequency_dict['h']);
    free(res.transformed_sequence);
    return 0;
}
