def isAlienSorted(words, order, n):
    order_dict = {char: i for i, char in enumerate(order)}

    # Check consecutive character constraint
    for word in words:
        if not word:
            continue
        count = 1
        for i in range(1, len(word)):
            if word[i] == word[i-1]:
                count += 1
                if count > n:
                    return False
            else:
                count = 1

    # Check lexicographical order
    for i in range(len(words) - 1):
        w1 = words[i]
        w2 = words[i+1]

        for j in range(min(len(w1), len(w2))):
            if w1[j] != w2[j]:
                if order_dict[w1[j]] > order_dict[w2[j]]:
                    return False
                break
        else:
            # If one word is a prefix of another, the shorter one must come first
            if len(w1) > len(w2):
                return False

    return True

# Test cases
tests = [
    ({"words": ["hello", "leetcode"], "order": "hlabcdefgijkmnopqrstuvwxyz", "n": 2}, True),
