content = "class Node<T> {
    T data;
    Node<T> next;

    public Node(T data) {
        this.data = data;
    }
}

public class CircularLinkedList<T> {
    Node<T> head;
    Node<T> tail;
    int size = 0;
    int capacity;

    public CircularLinkedList(int capacity) {
        this.capacity = capacity;
    }

    public void add(T data) {
        Node<T> newNode = new Node<>(data);
        if(size < capacity) {
            if(size == 0) {
                head = newNode;
                tail = newNode;
                tail.next = head;
            } else {
                tail.next = newNode;
                tail = newNode;
                tail.next = head;
            }
            size++;
        } else {
            if(head != tail) {
                head.data = data;
                head = head.next;
                tail = tail.next;
            } else {
                head.data = data;
            }
        }
    }

    public void printList() {
        Node<T> temp = head;
        if (size != 0) {
            do {
                System.out.println(temp.data);
                temp = temp.next;
            } while (temp != head);
        }
    }

    public static void main(String[] args) {
        CircularLinkedList<Integer> list = new CircularLinkedList<>(3);
        list.add(1);
        list.add(2);
        list.add(3);
        list.add(4); // Should overwrite 1
        list.printList();
    }
