import java.util.*;

public class Solution {
    public static void solve(int[] deck, int target) {
        int n = deck.length;
        Arrays.sort(deck);

        Deque<Integer> resultDeck = new ArrayDeque<>();
        // To simulate the process in reverse:
        // 1. Take the last element from the result deck and move it to the front
        // 2. Add the next smallest element from the sorted deck to the front
        for (int i = 0; i < n; i++) {
            if (!resultDeck.isEmpty()) {
                resultDeck.addFirst(resultDeck.removeLast());
            }
            resultDeck.addFirst(deck[i]);
        }

        Integer[] finalOrder = resultDeck.toArray(new Integer[0]);
        System.out.print("Deck Order: ");
        System.out.println(Arrays.toString(finalOrder));

        // The revealed sequence is just the sorted deck
        int position = -1;
        for (int i = 0; i < n; i++) {
            if (deck[i] == target) {
                position = i + 1;
                break;
            }
        }
        System.out.println("Target Position: " + position);
    }

    public static void main(String[] args) {
        int[] deck = {17, 13, 11, 2, 3, 5, 7};
        int target = 11;
        solve(deck, target);
    }
}
