Key differences handled:
1. **String Comparison**: Since C lacks `startswith` and `endswith`, I used `strncasecmp` for the prefix and a custom `ends_with` function using pointer arithmetic and `strcasecmp` for the suffix.
2. **Case Insensitivity**: Used `tolower` and `strcasecmp`/`strncasecmp` to mimic Python's `.lower()` behavior.
3. **Summation**: Implemented a loop in `calculateTotalSum` to replace the Python list comprehension, using a pre-filled array `char_to_int` for O(1) lookups.

```c
#include <stdio.h>
#include <string.h>
#include <ctype.h>

int char_to_int[26];

int ends_with(const char *str, const char *suffix) {
    size_t lenstr = strlen(str);
    size_t lensuffix = strlen(suffix);
    if (lensuffix > lenstr) return 0;
    return strcasecmp(str + lenstr - lensuffix, suffix) == 0;
}

int calculateTotalSum(const char* s) {
    int totalSum = 0;
    for (int i = 0; s[i] != '\0'; i++) {
        char c = tolower((unsigned char)s[i]);
        if (c >= 'a' && c <= 'z') {
            totalSum += char_to_int[c - 'a'];
        }
    }
    return totalSum;
}

void findLongestString(char* strings[], int numberOfStrings, char* prefixSuffix[], char** outLongest, int* outSum) {
    *outLongest = "";
    *outSum = 0;

    for (int i = 0; i < 26; i++) {
        char_to_int[i] = i + 1;
    }

    for (int i = 0; i < numberOfStrings; i++) {
        char *s = strings[i];
        if (strncasecmp(s, prefixSuffix[0], strlen(prefixSuffix[0])) == 0 
            && ends_with(s, prefixSuffix[1]) 
