#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

#define MAX_N 100

// Structure to represent a state in the priority queue
typedef struct {
    int cost;           // Total cost to reach this node
    int x, y;           // Current coordinates
    int path[MAX_N * MAX_N]; // Array to store the values of the path
    int path_len;       // Current length of the path
} Node;

// Priority Queue (Min-Heap) to store and sort nodes by cost
typedef struct {
    Node heap[MAX_N * MAX_N * 4];
    int size;
} PriorityQueue;

// Function to push a node into the min-heap
void push(PriorityQueue *pq, Node node) {
    pq->heap[pq->size] = node;
    int i = pq->size++;
    while (i > 0 && pq->heap[i].cost < pq->heap[(i - 1) / 2].cost) {
        Node temp = pq->heap[i];
        pq->heap[i] = pq->heap[(i - 1) / 2];
        pq->heap[(i - 1) / 2] = temp;
        i = (i - 1) / 2;
    }
}

// Function to pop the node with the minimum cost from the heap
Node pop(PriorityQueue *pq) {
    Node root = pq->heap[0];
    pq->heap[0] = pq->heap[--pq->size];
    int i = 0;
    while (i * 2 + 1 < pq->size) {
        int child = i * 2 + 1;
        if (child + 1 < pq->size && pq->heap[child + 1].cost < pq->heap[child].cost)
            child++;
        if (pq->heap[i].cost <= pq->heap[child].cost)
            break;
        Node temp = pq->heap[i];
        pq->heap[i] = pq->heap[child];
        pq->heap[child] = temp;
        i = child;
    }
    return root;
}

// Main translation of the minPath function
