content = "def temperature_conversion(initial_scale, final_scale, temp_value):
    error_message = 'Invalid temperature scale. Available scales are: Fahrenheit, Celsius, Kelvin, Rankine'
    initial_scale = initial_scale.lower()
    final_scale = final_scale.lower()

    if initial_scale not in ['fahrenheit', 'celsius', 'kelvin', 'rankine']:
        raise ValueError(error_message)

    if final_scale not in ['fahrenheit', 'celsius', 'kelvin', 'rankine']:
        raise ValueError(error_message)

    # Convert initial scale to Celsius as a common base
    if initial_scale == 'celsius':
        if temp_value < -273.15:
            raise ValueError('Temperature below absolute zero is not possible')
        celsius_val = temp_value
    elif initial_scale == 'kelvin':
        if temp_value < 0:
            raise ValueError('Temperature below absolute zero is not possible')
        celsius_val = temp_value - 273.15
    elif initial_scale == 'fahrenheit':
        if temp_value < -459.67:
            raise ValueError('Temperature below absolute zero is not possible')
        celsius_val = (temp_value - 32) / 1.8
    elif initial_scale == 'rankine':
        if temp_value < 0:
            raise ValueError('Temperature below absolute zero is not possible')
        celsius_val = (temp_value - 491.67) / 1.8

    # Convert Celsius base to final scale
    if final_scale == 'celsius':
        return celsius_val
    elif final_scale == 'kelvin':
        return celsius_val + 273.15
    elif final_scale == 'fahrenheit':
        return (celsius_val * 1.8) + 32
    elif final_scale == 'rankine':
        return (celsius_val + 273.15) * 1.8
