content = "#include <iostream>
#include <cmath>        
using namespace std;

void shellSort(float array[], int n) {
    for (int gap = n / 2; gap > 0; gap /= 2) {
        for (int i = gap; i < n; i += 1) {
            float temp = array[i];
            int j;
            for (j = i; j >= gap && round(array[j - gap]*1000)/1000 < round(temp*1000)/1000; j -= gap)
                array[j] = array[j - gap];
            array[j] = temp;
        }
    }
}

void printArray(float array[], int n) {
    for (int i = 0; i < n; i++)
        cout << array[i] << " ";
    cout << "\n";
}

int main() {
    float array[] = {1.12345, 3.98765, 2.76452, 5.10293, 4.85321};
    int n = sizeof(array)/sizeof(array[0]);
    cout << "Original array: \n";
    printArray(array, n);
    shellSort(array, n);
    cout << "\nSorted array in descending order: \n";
    printArray(array, n);
    return 0;
