                record.pop()
            elif op == 'D':
                record.append(record[-1] * 2)
            elif op == '+':
                record.append(record[-1] + record[-2])
            elif op == 'M':
                sorted_rec = sorted(record)
                n = len(sorted_rec)
                if n % 2 == 1:
                    median = sorted_rec[n // 2]
                else:
                    median = (sorted_rec[(n - 1) // 2] + sorted_rec[n // 2]) / 2
