final_answer("def is_perfect_square(x):
    if x <= 0:
        return False
    if x == 1:
        return True
    low, high = 0, x
    while low <= high:
        mid = (low + high) // 2
        squared = mid * mid
        if squared == x:
            return True
        elif squared < x:
            low = mid + 1
        else:
            high = mid - 1
    return False")
