Thought: I need to implement a solution that first recovers a binary tree from a preorder traversal string with depth indicators (dashes) and then calculates the maximum path sum in that tree. I'll write the code to a file and test it with the provided examples.
<code>
content = """
class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val = val
        self.left = left
        self.right = right

class Solution:
    def maxPathSum(self, root: TreeNode) -> int:
        self.max_sum = float('-inf')

        def max_gain(node):
            if not node:
                return 0
            left_gain = max(max_gain(node.left), 0)
            right_gain = max(max_gain(node.right), 0)
            self.max_sum = max(self.max_sum, node.val + left_gain + right_gain)
            return node.val + max(left_gain, right_gain)

        max_gain(root)
        return self.max_sum

    def recoverFromPreorder(self, S: str) -> TreeNode:
        stack, i = [], 0
        while i < len(S):
            level, val = 0, ""
            while i < len(S) and S[i] == '-':
                i, level = i + 1, level + 1
            while i < len(S) and S[i] != '-':
                i, val = i + 1, val + S[i]

            while len(stack) > level:
                stack.pop()

            node = TreeNode(int(val))
            if stack and stack[-1].left is None:
                stack[-1].left = node
            elif stack:
                stack[-1].right = node

            stack.append(node)

        return stack[0]

    def solve(self, S: str) -> int:
        root = self.recoverFromPreorder(S)
        return self.maxPathSum(root)

# Test cases
sol = Solution()
print(f"Example 1: {sol.solve('1-2--3--4-5--6--7')}")
print(f"Example 2: {sol.solve('1-2--3---4-5--6---7')}")
print(f"Example 3: {sol.solve('1-401--349---90--88')}")
"""
