import boto3
from botocore.exceptions import BotoCoreError, ClientError
from concurrent.futures import ThreadPoolExecutor

# Setting up logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')
logger = logging.getLogger(__name__)

class S3Manager:
    def __init__(self, region_name='us-east-1'):
        self.s3_resource = boto3.resource('s3', region_name=region_name)
        self.s3_client = boto3.client('s3', region_name=region_name)

    def create_bucket(self, bucket_name, region=None):
        try:
            if region is None:
                self.s3_resource.create_bucket(Bucket=bucket_name)
            else:
                self.s3_resource.create_bucket(
                    Bucket=bucket_name,
                    CreateBucketConfiguration={'LocationConstraint': region}
                )
            logger.info(f'Bucket {bucket_name} created successfully')
        except (BotoCoreError, ClientError) as e:
            logger.error(f'Error creating bucket {bucket_name}: {e}')

    def list_buckets(self):
        try:
            return [bucket.name for bucket in self.s3_resource.buckets.all()]
        except (BotoCoreError, ClientError) as e:
            logger.error(f'Error listing buckets: {e}')
            return []

    def upload_file(self, file_path, bucket_name, object_name=None, acl='private'):
        if object_name is None:
            object_name = file_path
        try:
            self.s3_resource.Bucket(bucket_name).upload_file(file_path, object_name, ExtraArgs={'ACL': acl})
            logger.info(f'Uploaded {file_path} to {bucket_name} as {object_name} with ACL {acl}')
        except (BotoCoreError, ClientError) as e:
            logger.error(f'Error uploading {file_path}: {e}')

    def download_file(self, bucket_name, object_name, file_path):
        try:
            self.s3_resource.Bucket(bucket_name).download_file(object_name, file_path)
            logger.info(f'Downloaded {object_name} from {bucket_name} to {file_path}')
        except (BotoCoreError, ClientError) as e:
            logger.error(f'Error downloading {object_name}: {e}')

    def delete_file(self, bucket_name, object_name):
        try:
            self.s3_resource.Object(bucket_name, object_name).delete()
            logger.info(f'Deleted {object_name} from {bucket_name}')
        except (BotoCoreError, ClientError) as e:
            logger.error(f'Error deleting {object_name}: {e}')

    def list_files(self, bucket_name):
        try:
            bucket = self.s3_resource.Bucket(bucket_name)
            return [obj.key for obj in bucket.objects.all()]
        except (BotoCoreError, ClientError) as e:
            logger.error(f'Error listing files in {bucket_name}: {e}')
            return []

    def set_acl(self, bucket_name, object_name, acl='private'):
        try:
            self.s3_client.put_object_acl(Bucket=bucket_name, Key=object_name, ACL=acl)
            logger.info(f'Set ACL of {object_name} in {bucket_name} to {acl}')
        except (BotoCoreError, ClientError) as e:
            logger.error(f'Error setting ACL for {object_name}: {e}')

    def upload_multiple_files(self, files_list, bucket_name, max_workers=5):
        # Handle concurrency using ThreadPoolExecutor
        with ThreadPoolExecutor(max_workers=max_workers) as executor:
            for file_path in files_list:
                executor.submit(self.upload_file, file_path, bucket_name)

if __name__ == '__main__':
    # Example usage (requires configured AWS credentials)
    manager = S3Manager()
    print('S3 Manager initialized.')
