public class Palindrome {

    public static void main(String[] args) {
        String test = "racecar";
        System.out.println("Is palindrome: " + isPalindrome(test));
        System.out.println("Palindromic substrings: " + getPalindromicSubstrings(test));
    }

    public static boolean isPalindrome(String str) {
        String cleanedStr = str.replaceAll("\W", "").toLowerCase();
        StringBuilder reversedCleanedStr = new StringBuilder(cleanedStr).reverse();
        return cleanedStr.equals(reversedCleanedStr.toString());
    }

    public static List<String> getPalindromicSubstrings(String str) {
        List<String> result = new ArrayList<>();
        String cleanedStr = str.replaceAll("\W", "");
        for (int i = 0; i < cleanedStr.length(); i++) {
            for (int j = i + 1; j <= cleanedStr.length(); j++) {
                String substring = cleanedStr.substring(i, j);
                if (isPalindrome(substring)) {
                    result.add(substring);
                }
            }
        }
        return result;
    }
