impl Agent {
    fn new(emotion: String, responses: Vec<String>) -> Self {
        Self {
            emotion,
            responses,
        }
    }

    fn respond(&self) -> &String {
        let idx = rand::thread_rng().gen_range(0, self.responses.len());
        &self.responses[idx]
    }
}

fn main() {
    let mut interactions = HashMap::new();

    let ecstasy = Agent::new(
        String::from("ecstasy"),
        vec![
            String::from("I'm feeling incredible!"),
            String::from("Today is a great day!"),
            String::from("I'm so happy that I could dance!"),
