        String::from("fury"),
        vec![
            String::from("I'm livid!"),
            String::from("Everything is terrible!"),
            String::from("I'm so angry I could scream!"),
        ],
    );

    interactions.insert(ecstasy.emotion.clone(), ecstasy);
    interactions.insert(fury.emotion.clone(), fury);

    let ecstasy_response = interactions.get("ecstasy").unwrap().respond();
    let fury_response = interactions.get("fury").unwrap().respond();

