Thought: I need to construct the URL from the given components: https, mypage, google, and search. The target URL will be `https://mypage.google.com/search` (assuming .com as a standard TLD for google). I will then implement the validation logic in a Python script, ensuring modularity and including unit tests as requested.
<code>
content = "import re
import unittest

# Modular validation functions

def validate_protocol(url):
    if not url.startswith("https://"):
        return "Error in protocol"
    return None

def validate_subdomain(url):
    try:
        # Extract subdomain: part between // and the first dot
        parts = url.split("//")[1].split("/")[0].split(".")
        subdomain = parts[0]
        if not re.match(r'^[a-z0-9]([a-z0-9-]*[a-z0-9])?$', subdomain):
            return "Error in subdomain"
    except IndexError:
        return "Error in subdomain"
    return None

def validate_primary_domain(url):
    try:
        # Extract domain part: everything from first dot to the first slash
        domain_full = url.split("//")[1].split("/")[0]
        parts = domain_full.split(".")
        if len(parts) < 3:
            return "Error in primary domain"

        # Primary domain is the second part, TLD is the last
        primary = parts[1]
        tld = parts[-1]

        if not re.match(r'^[a-z0-9]([a-z0-9-]*[a-z0-9])?$', primary):
            return "Error in primary domain"
        if not re.match(r'^[a-z]+$', tld):
            return "Error in primary domain"
    except IndexError:
        return "Error in primary domain"
    return None

def validate_resource_path(url):
    try:
        path = "/" + url.split("/", 3)[3] if len(url.split("/", 3)) > 3 else "/"
        if not re.match(r'^(/[a-z0-9_-]*)*$', path):
            return "Error in resource path"
    except IndexError:
        return "Error in resource path"
    return None

def validate_url(url):
    for func in [validate_protocol, validate_subdomain, validate_primary_domain, validate_resource_path]:
        error = func(url)
        if error: return error
    return "URL is valid"

# Unit Tests
class TestURLValidator(unittest.TestCase):
    def test_valid_url(self):
        self.assertEqual(validate_url("https://mypage.google.com/search"), "URL is valid")

    def test_invalid_protocol(self):
        self.assertEqual(validate_url("http://mypage.google.com/search"), "Error in protocol")

    def test_invalid_subdomain(self):
        self.assertEqual(validate_url("https://-mypage.google.com/search"), "Error in subdomain")

    def test_invalid_domain(self):
        self.assertEqual(validate_url("https://mypage.google/search"), "Error in primary domain")

    def test_invalid_path(self):
        self.assertEqual(validate_url("https://mypage.google.com/search!"), "Error in resource path")

if __name__ == "__main__":
    # Test the specific constructed URL
    test_url = "https://mypage.google.com/search"
    print(f"Testing URL: {test_url} -> {validate_url(test_url)}")

    # Run unit tests
    suite = unittest.TestLoader().loadTestsFromTestCase(TestURLValidator)
    unittest.TextTestRunner().run(suite)
"
