content = "import hashlib
import string

def fibonacci(n):
    if n <= 0: return []
    if n == 1: return [0]
    if n == 2: return [0, 1]
    fibo = [0, 1]
    while len(fibo) < n:
        fibo.append(fibo[-1] + fibo[-2])
    return fibo

def caesar_encrypt(text, shift=3):
    alphabet = string.ascii_lowercase + string.ascii_uppercase
    shifted = alphabet[shift:] + alphabet[:shift]
    table = str.maketrans(alphabet, shifted)
    return text.translate(table)

def caesar_decrypt(text, shift=3):
    alphabet = string.ascii_lowercase + string.ascii_uppercase
    shifted = alphabet[-shift:] + alphabet[:-shift]
    table = str.maketrans(alphabet, shifted)
    return text.translate(table)

def generate_fib_dict():
    # First five Fibonacci numbers: 0, 1, 1, 2, 3
    # Names corresponding to those values
    names = ['Zero', 'One', 'One', 'Two', 'Three']
    my_dict = {}
    for name in names:
        key = hashlib.sha256(name[:3].encode()).hexdigest()
        my_dict[key] = caesar_encrypt(name)
    return my_dict

def get_total_keys(d):
    return len(d)

if __name__ == '__main__':
    d = generate_fib_dict()
    print(f'Total keys: {get_total_keys(d)}')
    for k, v in d.items():
        print(f'Key: {k}, Encrypted: {v}, Decrypted: {caesar_decrypt(v)}')
